// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./ProjectRegistry.sol";

/**
 * @title FundManagement
 * @dev Manages escrow and milestone-based fund release for approved projects
 */
contract FundManagement is AccessControl, ReentrancyGuard, Pausable {
    bytes32 public constant AUTHORITY_ROLE = keccak256("AUTHORITY_ROLE");

    ProjectRegistry public projectRegistry;

    struct Milestone {
        uint256 milestoneId;
        uint256 projectId;
        string description;
        uint256 percentageAllocation;
        bool isCompleted;
        bool isApproved;
        uint256 completionDate;
        uint256 approvalDate;
        string verificationHash; // IPFS proof
        address completedBy;
        address approvedBy;
    }

    struct ProjectFunding {
        uint256 totalBudget;
        uint256 allocatedAmount;
        uint256 releasedAmount;
        uint256 remainingAmount;
        bool isFunded;
        uint256 fundedAt;
        uint256 milestoneCount;
        mapping(uint256 => Milestone) milestones;
    }

    // State variables
    mapping(uint256 => ProjectFunding) private projectFunds;
    mapping(uint256 => uint256[]) private projectMilestones; // projectId => milestoneIds
    uint256 private milestoneCounter;

    uint256 public constant MAX_DAILY_WITHDRAWAL = 1000 ether;
    mapping(uint256 => uint256) public dailyWithdrawals; // projectId => amount today
    mapping(uint256 => uint256) public lastWithdrawalDay; // projectId => day

    // Events
    event FundsAllocated(
        uint256 indexed projectId,
        uint256 amount,
        uint256 timestamp
    );

    event MilestoneCreated(
        uint256 indexed projectId,
        uint256 indexed milestoneId,
        string description,
        uint256 percentage
    );

    event MilestoneCompleted(
        uint256 indexed projectId,
        uint256 indexed milestoneId,
        address completedBy,
        string verificationHash
    );

    event MilestoneApproved(
        uint256 indexed projectId,
        uint256 indexed milestoneId,
        address approvedBy
    );

    event FundsReleased(
        uint256 indexed projectId,
        uint256 indexed milestoneId,
        address indexed contractor,
        uint256 amount
    );

    event EmergencyWithdrawal(
        uint256 indexed projectId,
        address indexed admin,
        uint256 amount,
        string reason
    );

    constructor(address _projectRegistryAddress) {
        projectRegistry = ProjectRegistry(_projectRegistryAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Allocate funds to an approved project
     */
    function allocateFunds(uint256 _projectId) 
        external 
        payable
        onlyRole(DEFAULT_ADMIN_ROLE)
        nonReentrant
        whenNotPaused
    {
        require(msg.value > 0, "Amount must be greater than 0");

        ProjectFunding storage funding = projectFunds[_projectId];
        require(!funding.isFunded, "Project already funded");

        // Verify project is approved
        (
            ,
            ,
            ,
            uint256 budgetRequested,
            ProjectRegistry.ProjectStatus status,
            ,
        ) = projectRegistry.getProjectAnonymized(_projectId);

        require(
            status == ProjectRegistry.ProjectStatus.Approved,
            "Project not approved"
        );
        require(msg.value >= budgetRequested, "Insufficient funds");

        funding.totalBudget = budgetRequested;
        funding.allocatedAmount = msg.value;
        funding.remainingAmount = msg.value;
        funding.isFunded = true;
        funding.fundedAt = block.timestamp;

        emit FundsAllocated(_projectId, msg.value, block.timestamp);
    }

    /**
     * @dev Create milestone for a project
     */
    function createMilestone(
        uint256 _projectId,
        string memory _description,
        uint256 _percentageAllocation
    ) 
        external 
        nonReentrant
        returns (uint256)
    {
        ProjectFunding storage funding = projectFunds[_projectId];
        require(funding.isFunded, "Project not funded");
        require(_percentageAllocation > 0 && _percentageAllocation <= 100, "Invalid percentage");
        require(bytes(_description).length > 0, "Description required");

        // Verify total percentage doesn't exceed 100%
        uint256 totalPercentage = 0;
        uint256[] memory milestones = projectMilestones[_projectId];
        for (uint256 i = 0; i < milestones.length; i++) {
            totalPercentage += funding.milestones[milestones[i]].percentageAllocation;
        }
        require(
            totalPercentage + _percentageAllocation <= 100,
            "Total percentage exceeds 100%"
        );

        milestoneCounter++;
        uint256 newMilestoneId = milestoneCounter;

        Milestone storage milestone = funding.milestones[newMilestoneId];
        milestone.milestoneId = newMilestoneId;
        milestone.projectId = _projectId;
        milestone.description = _description;
        milestone.percentageAllocation = _percentageAllocation;
        milestone.isCompleted = false;
        milestone.isApproved = false;

        projectMilestones[_projectId].push(newMilestoneId);
        funding.milestoneCount++;

        emit MilestoneCreated(_projectId, newMilestoneId, _description, _percentageAllocation);

        return newMilestoneId;
    }

    /**
     * @dev Mark milestone as completed with proof
     */
    function completeMilestone(
        uint256 _projectId,
        uint256 _milestoneId,
        string memory _verificationHash
    ) 
        external 
        nonReentrant
    {
        ProjectFunding storage funding = projectFunds[_projectId];
        Milestone storage milestone = funding.milestones[_milestoneId];

        require(milestone.projectId == _projectId, "Milestone not found");
        require(!milestone.isCompleted, "Milestone already completed");
        require(bytes(_verificationHash).length > 0, "Verification proof required");

        milestone.isCompleted = true;
        milestone.completionDate = block.timestamp;
        milestone.verificationHash = _verificationHash;
        milestone.completedBy = msg.sender;

        emit MilestoneCompleted(_projectId, _milestoneId, msg.sender, _verificationHash);
    }

    /**
     * @dev Approve milestone and release funds
     */
    function approveMilestone(uint256 _projectId, uint256 _milestoneId) 
        external 
        onlyRole(AUTHORITY_ROLE)
        nonReentrant
        whenNotPaused
    {
        ProjectFunding storage funding = projectFunds[_projectId];
        Milestone storage milestone = funding.milestones[_milestoneId];

        require(milestone.projectId == _projectId, "Milestone not found");
        require(milestone.isCompleted, "Milestone not completed");
        require(!milestone.isApproved, "Milestone already approved");

        milestone.isApproved = true;
        milestone.approvalDate = block.timestamp;
        milestone.approvedBy = msg.sender;

        emit MilestoneApproved(_projectId, _milestoneId, msg.sender);

        // Automatically release funds
        _releaseFunds(_projectId, _milestoneId);
    }

    /**
     * @dev Internal function to release funds to contractor
     */
    function _releaseFunds(uint256 _projectId, uint256 _milestoneId) 
        private 
    {
        ProjectFunding storage funding = projectFunds[_projectId];
        Milestone storage milestone = funding.milestones[_milestoneId];

        require(milestone.isApproved, "Milestone not approved");

        uint256 releaseAmount = (funding.totalBudget * milestone.percentageAllocation) / 100;
        require(funding.remainingAmount >= releaseAmount, "Insufficient funds");

        // Check daily withdrawal limit
        uint256 currentDay = block.timestamp / 1 days;
        if (lastWithdrawalDay[_projectId] != currentDay) {
            dailyWithdrawals[_projectId] = 0;
            lastWithdrawalDay[_projectId] = currentDay;
        }
        require(
            dailyWithdrawals[_projectId] + releaseAmount <= MAX_DAILY_WITHDRAWAL,
            "Daily withdrawal limit exceeded"
        );

        // Get contractor address
        address contractor = projectRegistry.getContractorWallet(_projectId);
        require(contractor != address(0), "Invalid contractor address");

        // Update state before transfer (CEI pattern)
        funding.releasedAmount += releaseAmount;
        funding.remainingAmount -= releaseAmount;
        dailyWithdrawals[_projectId] += releaseAmount;

        // Transfer funds
        (bool success, ) = payable(contractor).call{value: releaseAmount}("");
        require(success, "Transfer failed");

        emit FundsReleased(_projectId, _milestoneId, contractor, releaseAmount);
    }

    /**
     * @dev Emergency withdrawal by admin
     */
    function emergencyWithdraw(uint256 _projectId, string memory _reason) 
        external 
        onlyRole(DEFAULT_ADMIN_ROLE)
        nonReentrant
    {
        require(bytes(_reason).length > 0, "Reason required");

        ProjectFunding storage funding = projectFunds[_projectId];
        uint256 amount = funding.remainingAmount;
        require(amount > 0, "No funds to withdraw");

        funding.remainingAmount = 0;

        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Transfer failed");

        emit EmergencyWithdrawal(_projectId, msg.sender, amount, _reason);
    }

    /**
     * @dev Get project funding details
     */
    function getProjectFunding(uint256 _projectId) 
        external 
        view 
        returns (
            uint256 totalBudget,
            uint256 allocatedAmount,
            uint256 releasedAmount,
            uint256 remainingAmount,
            bool isFunded,
            uint256 fundedAt,
            uint256 milestoneCount
        ) 
    {
        ProjectFunding storage funding = projectFunds[_projectId];
        return (
            funding.totalBudget,
            funding.allocatedAmount,
            funding.releasedAmount,
            funding.remainingAmount,
            funding.isFunded,
            funding.fundedAt,
            funding.milestoneCount
        );
    }

    /**
     * @dev Get milestone details
     */
    function getMilestone(uint256 _projectId, uint256 _milestoneId) 
        external 
        view 
        returns (Milestone memory) 
    {
        return projectFunds[_projectId].milestones[_milestoneId];
    }

    /**
     * @dev Get all milestones for a project
     */
    function getProjectMilestones(uint256 _projectId) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return projectMilestones[_projectId];
    }

    /**
     * @dev Get milestone completion percentage
     */
    function getMilestoneProgress(uint256 _projectId) 
        external 
        view 
        returns (uint256 completedPercentage, uint256 approvedPercentage) 
    {
        ProjectFunding storage funding = projectFunds[_projectId];
        uint256[] memory milestones = projectMilestones[_projectId];

        uint256 completed = 0;
        uint256 approved = 0;

        for (uint256 i = 0; i < milestones.length; i++) {
            Milestone storage milestone = funding.milestones[milestones[i]];
            if (milestone.isCompleted) {
                completed += milestone.percentageAllocation;
            }
            if (milestone.isApproved) {
                approved += milestone.percentageAllocation;
            }
        }

        return (completed, approved);
    }

    /**
     * @dev Pause contract
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Unpause contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    /**
     * @dev Receive function to accept ETH
     */
    receive() external payable {}
}

contracts/ProjectRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title ProjectRegistry
 * @dev Manages project submissions with comprehensive document storage
 */
contract ProjectRegistry is AccessControl, ReentrancyGuard, Pausable {
    bytes32 public constant PROJECT_MANAGER_ROLE = keccak256("PROJECT_MANAGER_ROLE");
    bytes32 public constant AUTHORITY_ROLE = keccak256("AUTHORITY_ROLE");

    enum ProjectStatus {
        Pending,
        UnderReview,
        Approved,
        Rejected,
        InProgress,
        Completed
    }

    struct DocumentStorage {
        string pdfDocumentHash;      // Main project document
        string labReportHash;         // Lab/technical report
        string[] geoTaggedPhotoHashes; // Array of photo hashes
        bytes digitalSignatureHash;   // Digital signature
        string vendorInvoiceHash;     // Invoice document
        string gpsLatitude;           // GPS coordinates
        string gpsLongitude;
    }

    struct Project {
        uint256 projectId;
        address projectManager;
        string title;
        string description;
        uint256 budgetRequested;
        ProjectStatus status;
        uint256 createdAt;
        uint256 approvedAt;
        address contractorWallet;     // Hidden during review
        DocumentStorage documents;
        string rejectionReason;
        string revisionComments;
    }

    // State variables
    uint256 private projectCounter;
    mapping(uint256 => Project) private projects;
    mapping(address => uint256[]) private managerProjects;
    mapping(ProjectStatus => uint256[]) private projectsByStatus;

    // Events
    event ProjectCreated(
        uint256 indexed projectId,
        address indexed projectManager,
        string title,
        uint256 budgetRequested
    );

    event ProjectSubmittedForReview(
        uint256 indexed projectId,
        address indexed assignedAuthority
    );

    event DocumentsUploaded(
        uint256 indexed projectId,
        string[] ipfsHashes
    );

    event ProjectStatusUpdated(
        uint256 indexed projectId,
        ProjectStatus oldStatus,
        ProjectStatus newStatus
    );

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Create a new project with all documentation
     */
    function createProject(
        string memory _title,
        string memory _description,
        uint256 _budgetRequested,
        address _contractorWallet,
        string memory _pdfDocumentHash,
        string memory _labReportHash,
        string[] memory _geoTaggedPhotoHashes,
        bytes memory _digitalSignatureHash,
        string memory _vendorInvoiceHash,
        string memory _gpsLatitude,
        string memory _gpsLongitude
    ) external whenNotPaused returns (uint256) {
        require(bytes(_title).length > 0, "Title required");
        require(_budgetRequested > 0, "Budget must be greater than 0");
        require(_contractorWallet != address(0), "Invalid contractor address");
        require(bytes(_pdfDocumentHash).length > 0, "PDF document required");

        projectCounter++;
        uint256 newProjectId = projectCounter;

        DocumentStorage memory docs = DocumentStorage({
            pdfDocumentHash: _pdfDocumentHash,
            labReportHash: _labReportHash,
            geoTaggedPhotoHashes: _geoTaggedPhotoHashes,
            digitalSignatureHash: _digitalSignatureHash,
            vendorInvoiceHash: _vendorInvoiceHash,
            gpsLatitude: _gpsLatitude,
            gpsLongitude: _gpsLongitude
        });

        Project storage newProject = projects[newProjectId];
        newProject.projectId = newProjectId;
        newProject.projectManager = msg.sender;
        newProject.title = _title;
        newProject.description = _description;
        newProject.budgetRequested = _budgetRequested;
        newProject.status = ProjectStatus.Pending;
        newProject.createdAt = block.timestamp;
        newProject.contractorWallet = _contractorWallet;
        newProject.documents = docs;

        managerProjects[msg.sender].push(newProjectId);
        projectsByStatus[ProjectStatus.Pending].push(newProjectId);

        emit ProjectCreated(newProjectId, msg.sender, _title, _budgetRequested);
        emit DocumentsUploaded(newProjectId, _geoTaggedPhotoHashes);

        return newProjectId;
    }

    /**
     * @dev Get full project details (admin/manager only)
     */
    function getProject(uint256 _projectId) 
        external 
        view 
        returns (Project memory) 
    {
        require(_projectId > 0 && _projectId <= projectCounter, "Invalid project ID");
        Project memory project = projects[_projectId];

        // Only manager, admin, or assigned authority can see full details
        require(
            msg.sender == project.projectManager ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender) ||
            hasRole(AUTHORITY_ROLE, msg.sender),
            "Unauthorized"
        );

        return project;
    }

    /**
     * @dev Get anonymized project (contractor address hidden)
     */
    function getProjectAnonymized(uint256 _projectId) 
        external 
        view 
        returns (
            uint256 projectId,
            string memory title,
            string memory description,
            uint256 budgetRequested,
            ProjectStatus status,
            uint256 createdAt,
            DocumentStorage memory documents
        ) 
    {
        require(_projectId > 0 && _projectId <= projectCounter, "Invalid project ID");
        Project memory project = projects[_projectId];

        return (
            project.projectId,
            project.title,
            project.description,
            project.budgetRequested,
            project.status,
            project.createdAt,
            project.documents
        );
    }

    /**
     * @dev Update project status (internal or authorized only)
     */
    function updateProjectStatus(
        uint256 _projectId,
        ProjectStatus _newStatus,
        string memory _comments
    ) external {
        require(
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender) ||
            hasRole(AUTHORITY_ROLE, msg.sender),
            "Unauthorized"
        );
        require(_projectId > 0 && _projectId <= projectCounter, "Invalid project ID");

        Project storage project = projects[_projectId];
        ProjectStatus oldStatus = project.status;

        project.status = _newStatus;

        if (_newStatus == ProjectStatus.Approved) {
            project.approvedAt = block.timestamp;
        } else if (_newStatus == ProjectStatus.Rejected) {
            project.rejectionReason = _comments;
        }

        // Update status mapping
        _removeFromStatusArray(oldStatus, _projectId);
        projectsByStatus[_newStatus].push(_projectId);

        emit ProjectStatusUpdated(_projectId, oldStatus, _newStatus);
    }

    /**
     * @dev Get projects by status
     */
    function getProjectsByStatus(ProjectStatus _status) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return projectsByStatus[_status];
    }

    /**
     * @dev Get projects by manager
     */
    function getProjectsByManager(address _manager) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return managerProjects[_manager];
    }

    /**
     * @dev Get total number of projects
     */
    function getTotalProjects() external view returns (uint256) {
        return projectCounter;
    }

    /**
     * @dev Get contractor wallet (only after approval for transparency)
     */
    function getContractorWallet(uint256 _projectId) 
        external 
        view 
        returns (address) 
    {
        require(_projectId > 0 && _projectId <= projectCounter, "Invalid project ID");
        Project memory project = projects[_projectId];

        // Only show contractor after approval (for public transparency)
        require(
            project.status == ProjectStatus.Approved ||
            project.status == ProjectStatus.InProgress ||
            project.status == ProjectStatus.Completed ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Contractor info not yet public"
        );

        return project.contractorWallet;
    }

    /**
     * @dev Add revision comments
     */
    function addRevisionComments(uint256 _projectId, string memory _comments) 
        external 
    {
        require(hasRole(AUTHORITY_ROLE, msg.sender), "Only authority can add comments");
        require(_projectId > 0 && _projectId <= projectCounter, "Invalid project ID");

        projects[_projectId].revisionComments = _comments;
    }

    /**
     * @dev Internal function to remove project from status array
     */
    function _removeFromStatusArray(ProjectStatus _status, uint256 _projectId) 
        private 
    {
        uint256[] storage statusArray = projectsByStatus[_status];
        for (uint256 i = 0; i < statusArray.length; i++) {
            if (statusArray[i] == _projectId) {
                statusArray[i] = statusArray[statusArray.length - 1];
                statusArray.pop();
                break;
            }
        }
    }

    /**
     * @dev Grant project manager role
     */
    function grantProjectManagerRole(address _manager) 
        external 
        onlyRole(DEFAULT_ADMIN_ROLE) 
    {
        grantRole(PROJECT_MANAGER_ROLE, _manager);
    }

    /**
     * @dev Pause contract (emergency)
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Unpause contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

